import { HealthService } from '../../services/health.service.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../_shared/screen-status.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';
import { documentStyleSheet } from '../../utils/css.js';
import './exercise-create-form/exercise-create-form.component.js';
import type { ExerciseCreateForm } from './exercise-create-form/exercise-create-form.component.js';
import type { Exercise, NewExercise } from '@motivation/shared';
import type { ScreenComponent } from '../../types/screen-component.js';
import stylesText from './health-exercises-screen.css?inline';

documentStyleSheet(stylesText);

/**
 * Exercise library management screen at `/health/exercises` (story 177). Lists
 * the catalogue with search, lets the user add (reusing exercise-create-form),
 * edit (same form in edit mode), and archive/unarchive. One form shows at a time
 * in a holder above the list. Refetches on mount.
 */
export class HealthExercisesScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private contentRoot: HTMLElement | null = null;
    private formHolder: HTMLElement | null = null;
    private listRoot: HTMLElement | null = null;
    private searchInput: HTMLInputElement | null = null;
    private showArchived = false;
    private exercises: Exercise[] = [];

    private readonly log = createComponentLogger('health-exercises-screen');
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Exercises', 'health', '/health');
        this.contentRoot = page.content;

        const controls = document.createElement('div');
        controls.className = 'exlib__controls';

        const addBtn = document.createElement('button');
        addBtn.type = 'button';
        addBtn.className = 'exlib__btn exlib__btn--primary';
        addBtn.textContent = '+ Add exercise';
        addBtn.dataset.testid = 'exlib-add';
        addBtn.addEventListener('click', () => this.openAddForm());

        this.searchInput = document.createElement('input');
        this.searchInput.className = 'exlib__search';
        this.searchInput.placeholder = 'Search exercises…';
        this.searchInput.dataset.testid = 'exlib-search';
        this.searchInput.addEventListener('input', () => this.renderList());

        const archivedLabel = document.createElement('label');
        archivedLabel.className = 'exlib__archived-toggle';
        const archivedCb = document.createElement('input');
        archivedCb.type = 'checkbox';
        archivedCb.dataset.testid = 'exlib-show-archived';
        archivedCb.addEventListener('change', () => {
            this.showArchived = archivedCb.checked;
            void this.load();
        });
        archivedLabel.append(archivedCb, document.createTextNode(' Show archived'));

        controls.append(addBtn, this.searchInput, archivedLabel);

        this.formHolder = document.createElement('div');
        this.formHolder.className = 'exlib__form-holder';

        this.listRoot = document.createElement('ul');
        this.listRoot.className = 'exlib__list';

        this.statusNodes.loadingNode.textContent = 'Loading exercises…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.load(); });

        this.contentRoot.append(
            this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode,
            controls, this.formHolder, this.listRoot,
        );

        void this.load();
    }

    private async load(): Promise<void> {
        return safeExec(this, this.log, async () => {
            this.exercises = await HealthService.listExercises({ includeArchived: this.showArchived });
            this.renderList();
        });
    }

    private renderList(): void {
        if (!this.listRoot) return;
        const q = (this.searchInput?.value ?? '').trim().toLowerCase();
        const matches = q
            ? this.exercises.filter((e) => e.display_name.toLowerCase().includes(q) || e.canonical_name.toLowerCase().includes(q))
            : this.exercises;

        if (matches.length === 0) {
            const empty = document.createElement('li');
            empty.className = 'exlib__empty';
            empty.textContent = q ? 'No matching exercises.' : 'No exercises yet — add one.';
            this.listRoot.replaceChildren(empty);
            return;
        }

        this.listRoot.replaceChildren(...matches.map((ex) => this.renderRow(ex)));
    }

    private renderRow(ex: Exercise): HTMLElement {
        const row = document.createElement('li');
        row.className = 'exlib__row';
        if (ex.archived_at) row.classList.add('exlib__row--archived');

        const info = document.createElement('div');
        info.className = 'exlib__info';
        const name = document.createElement('span');
        name.className = 'exlib__name';
        name.textContent = ex.display_name;
        const meta = document.createElement('span');
        meta.className = 'exlib__meta';
        meta.textContent = `${ex.category} · ${ex.default_unit}${ex.archived_at ? ' · archived' : ''}`;
        info.append(name, meta);

        const actions = document.createElement('div');
        actions.className = 'exlib__row-actions';

        const editBtn = document.createElement('button');
        editBtn.type = 'button';
        editBtn.className = 'exlib__btn';
        editBtn.textContent = 'Edit';
        editBtn.addEventListener('click', () => this.openEditForm(ex));

        const archiveBtn = document.createElement('button');
        archiveBtn.type = 'button';
        archiveBtn.className = 'exlib__btn';
        archiveBtn.textContent = ex.archived_at ? 'Unarchive' : 'Archive';
        archiveBtn.addEventListener('click', () => this.toggleArchive(ex));

        actions.append(editBtn, archiveBtn);
        row.append(info, actions);
        return row;
    }

    private openAddForm(): void {
        const form = this.mountForm();
        form.onSubmit = (payload) => { void this.handleCreate(payload, form); };
    }

    private openEditForm(ex: Exercise): void {
        const form = this.mountForm();
        form.exercise = ex;
        form.onSubmit = (payload) => { void this.handleUpdate(ex.id, payload, form); };
    }

    private mountForm(): ExerciseCreateForm {
        const form = document.createElement('exercise-create-form') as ExerciseCreateForm;
        form.onCancel = () => this.clearForm();
        this.formHolder!.replaceChildren(form);
        return form;
    }

    private clearForm(): void {
        this.formHolder?.replaceChildren();
    }

    private async handleCreate(payload: NewExercise, form: ExerciseCreateForm): Promise<void> {
        try {
            await HealthService.createExercise(payload);
            this.clearForm();
            await this.load();
        } catch (err) {
            this.log.warn('Failed to create exercise', { err });
            form.showError('Could not create exercise. It may already exist.');
        }
    }

    private async handleUpdate(id: string, payload: NewExercise, form: ExerciseCreateForm): Promise<void> {
        try {
            await HealthService.updateExercise(id, payload);
            this.clearForm();
            await this.load();
        } catch (err) {
            this.log.warn('Failed to update exercise', { err });
            form.showError('Could not save changes.');
        }
    }

    private async toggleArchive(ex: Exercise): Promise<void> {
        return safeExec(this, this.log, async () => {
            if (ex.archived_at) {
                await HealthService.unarchiveExercise(ex.id);
            } else {
                await HealthService.archiveExercise(ex.id);
            }
            await this.load();
        });
    }
}

customElements.define('health-exercises-screen', HealthExercisesScreen);
